#include <stdio.h>

int main() {
    int n;
    scanf("%d", &n);
    int s[n];
    for (int i = 0; i < n; i++) {
        scanf("%d", &s[i]);
    }
    int a = 0;
    for (int i = 0; i <= n; i++) {
        int x = 0;
        for (int j = 0; j < i; j++) {
            if (s[j] == 0) {
                x++;
            }
        }
        int y = 0;
        for (int j = i; j < n; j++) {
            if (s[j] == 1) {
                y++;
            }
        }
        if (x + y > a) {
            a = x + y;
        }
    }
    printf("%d\n", a);
    return 0;
}
